// Extract customer data and message details
const event = $input.first().json.events[0];
const userId = event.source.userId;
const messageText = event.message.text;
const messageId = event.message.id;
const timestamp = new Date(event.timestamp).toISOString();

// Check if message has image
const hasImage = event.message.type === 'image';
const imageId = hasImage ? event.message.id : null;

// Extract issue details using simple text processing
const issueData = {
  userId: userId,
  messageId: messageId,
  originalText: messageText,
  timestamp: timestamp,
  hasImage: hasImage,
  imageId: imageId,
  urgency: messageText.toLowerCase().includes('urgent') ? 'high' : 'normal',
  category: extractCategory(messageText)
};

function extractCategory(text) {
  const lowerText = text.toLowerCase();
  if (lowerText.includes('bug') || lowerText.includes('error')) return 'bug';
  if (lowerText.includes('feature') || lowerText.includes('request')) return 'feature';
  if (lowerText.includes('login') || lowerText.includes('password')) return 'account';
  return 'general';
}

return issueData;

