// Parse Gemini response and prepare Redmine issue data
const geminiResponse = JSON.parse($input.first().json.text);
const customerData = $('Extract Customer Data').item.json;
const hasImage = $('Extract Customer Data').item.json.hasImage;

// Map assignee type to actual developer
const assigneeMap = {
  'frontend': 'john.doe',
  'backend': 'jane.smith', 
  'devops': 'mike.wilson',
  'qa': 'sarah.jones'
};

const assignee = assigneeMap[geminiResponse.assignee_type] || 'john.doe';

// Prepare Redmine issue payload
const redmineIssue = {
  issue: {
    project_id: 1, // Replace with your project ID
    subject: `[LINE Support] ${geminiResponse.summary}`,
    description: `**Customer Issue:**\n${customerData.originalText}\n\n**AI Analysis:**\n${geminiResponse.summary}\n\n**Recommended Steps:**\n${geminiResponse.steps.map((step, i) => `${i+1}. ${step}`).join('\n')}\n\n**Customer ID:** ${customerData.userId}\n**Timestamp:** ${customerData.timestamp}\n**Category:** ${customerData.category}`,
    priority_id: getPriorityId(geminiResponse.priority),
    assigned_to_id: getAssigneeId(assignee),
    estimated_hours: geminiResponse.estimated_hours,
    custom_fields: [
      {
        id: 1, // Custom field for LINE User ID
        value: customerData.userId
      },
      {
        id: 2, // Custom field for urgency
        value: customerData.urgency
      }
    ]
  }
};

function getPriorityId(priority) {
  const priorityMap = {
    'Low': 1,
    'Normal': 2, 
    'High': 3,
    'Urgent': 4
  };
  return priorityMap[priority] || 2;
}

function getAssigneeId(username) {
  const userMap = {
    'john.doe': 1,
    'jane.smith': 2,
    'mike.wilson': 3,
    'sarah.jones': 4
  };
  return userMap[username] || 1;
}

return {
  redminePayload: redmineIssue,
  assigneeName: assignee,
  priority: geminiResponse.priority,
  summary: geminiResponse.summary,
  hasImage: hasImage
};

// Prepare Teams message
const issueData = $('Create Redmine Issue').item.json.issue;
const redmineData = $('Prepare Redmine Issue').item.json;
const customerData = $('Extract Customer Data').item.json;

// Create rich Teams message card
const teamsMessage = {
  "@type": "MessageCard",
  "@context": "https://schema.org/extensions",
  "summary": `New support issue assigned: ${redmineData.summary}`,
  "themeColor": getPriorityColor(redmineData.priority),
  "sections": [
    {
      "activityTitle": "🎫 New Support Issue Assigned",
      "activitySubtitle": `Priority: ${redmineData.priority}`,
      "facts": [
        {
          "name": "Issue ID:",
          "value": `#${issueData.id}`
        },
        {
          "name": "Customer:",
          "value": customerData.userId
        },
        {
          "name": "Category:",
          "value": customerData.category
        },
        {
          "name": "Priority:",
          "value": redmineData.priority
        },
        {
          "name": "Assigned to:", 
          "value": redmineData.assigneeName
        }
      ],
      "text": `**Original Message:**\n${customerData.originalText}\n\n**AI Summary:**\n${redmineData.summary}`
    }
  ],
  "potentialAction": [
    {
      "@type": "OpenUri",
      "name": "View in Redmine",
      "targets": [
        {
          "os": "default",
          "uri": `https://your-redmine.company.com/issues/${issueData.id}`
        }
      ]
    },
    {
      "@type": "OpenUri", 
      "name": "Reply to Customer",
      "targets": [
        {
          "os": "default",
          "uri": `https://manager.line.biz/account/@your-bot/talk/${customerData.userId}`
        }
      ]
    }
  ]
};

function getPriorityColor(priority) {
  const colorMap = {
    'Low': '28a745',
    'Normal': '007bff', 
    'High': 'ffc107',
    'Urgent': 'dc3545'
  };
  return colorMap[priority] || '007bff';
}

return {
  teamsPayload: teamsMessage,
  assigneeName: redmineData.assigneeName
};

